#nullable enable // autogenerated

using System.Collections.Generic;
using System.Linq;
using MVZ2Logic.Definitions;
using MVZ2Logic.Games;
using PVZEngine;
using PVZEngine.Base;
using UnityEngine;

namespace MVZ2Logic.Maps
{
    public abstract class MapElementDefinition : Definition, ICachedDefinition
    {
        public MapElementDefinition(string nsp, string name) : base(nsp, name)
        {
        }
        public void AddBehaviourID(NamespaceID behaviour)
        {
            behaviours.Add(behaviour);
        }
        public bool RemoveBehaviourID(NamespaceID behaviour)
        {
            return behaviours.Remove(behaviour);
        }
        public bool HasBehaviourID(MapElementBehaviourDefinition behaviour)
        {
            return HasBehaviour(behaviour.GetID());
        }
        public bool HasBehaviourID(NamespaceID id)
        {
            return behaviours.Contains(id);
        }
        public bool HasBehaviour(MapElementBehaviourDefinition behaviour)
        {
            return behaviourCaches.Contains(behaviour);
        }
        public bool HasBehaviour<T>()
        {
            return behaviourCaches.Exists(b => b is T);
        }
        public bool HasBehaviour(NamespaceID id)
        {
            return behaviourCaches.Exists(b => b.GetID() == id);
        }
        void ICachedDefinition.CacheContents(IGameContent content)
        {
            behaviourCaches.Clear();
            foreach (var behaviourID in behaviours)
            {
                var behaviour = content.GetMapElementBehaviourDefinition(behaviourID);
                if (behaviour == null)
                {
                    Debug.LogWarning($"Cannot find map element behaviour with ID {behaviourID}");
                    continue;
                }
                behaviourCaches.Add(behaviour);
            }
        }
        void ICachedDefinition.ClearCaches()
        {
            behaviourCaches.Clear();
        }
        public T? GetBehaviour<T>()
        {
            foreach (var behaviour in behaviourCaches)
            {
                if (behaviour is T tBehaviour)
                    return tBehaviour;
            }
            return default;
        }
        public MapElementBehaviourDefinition GetBehaviourAt(int behaviour)
        {
            return behaviourCaches[behaviour];
        }
        public int GetBehaviourCount()
        {
            return behaviourCaches.Count;
        }
        public T[] GetBehaviours<T>()
        {
            return behaviourCaches.OfType<T>().ToArray();
        }
        public void OnClick(IMapElement element)
        {
            foreach (var behaviour in behaviourCaches)
            {
                behaviour.OnClick(element);
            }
        }
        public sealed override string GetDefinitionType() => LogicDefinitionTypes.MAP_ELEMENT;
        private List<NamespaceID> behaviours = new List<NamespaceID>();
        private List<MapElementBehaviourDefinition> behaviourCaches = new List<MapElementBehaviourDefinition>();
    }
}
